#include <iostream>
#include <string>
#include <vector>
#include <sstream>

// This function encapsulates the core logic of the program being tested.
// It simulates the output that the main program would produce for a given integer input.
std::string run_program_logic(int num_input) {
    std::stringstream ss_out;
    std::string result_message;

    // Mimics the three independent 'if' statements from the original code
    if (num_input > 0) {
        result_message = "The number is definitely positive.";
    }
    if (num_input < 0) {
        result_message = "The number is certainly negative.";
    }
    if (num_input == 0) {
        result_message = "The number is exactly zero.";
    }
    ss_out << result_message;
    return ss_out.str();
}

int main() {
    std::vector<std::pair<int, std::string>> test_cases_data = {
        {15, "The number is definitely positive."},
        {-8, "The number is certainly negative."},
        {0, "The number is exactly zero."}
    };

    for (const auto& tc : test_cases_data) {
        std::string actual_output = run_program_logic(tc.first);
        if (actual_output == tc.second) {
            // Test passed
        } else {
            std::cerr << "Test failed for input: " << tc.first
                      << ". Expected: \"" << tc.second << "\", Got: \"" << actual_output << "\"" << std::endl;
            return 1; // Indicate failure
        }
    }
    return 0; // Indicate success
}
